package online.yudream.base.infra.platform.wiki.service;
import online.yudream.base.domain.platform.capability.enumerate.CapabilityType; import online.yudream.base.domain.platform.capability.service.CapabilityProvider; import online.yudream.base.domain.platform.capability.valobj.*; import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty; import org.springframework.stereotype.Component; import java.util.*; import java.util.concurrent.atomic.AtomicBoolean;
@Component @ConditionalOnProperty(prefix="yudream.platform.capabilities.wiki",name="enabled",havingValue="true") public class WikiCapabilityProvider implements CapabilityProvider {public static final String CODE="wiki";private final AtomicBoolean enabled=new AtomicBoolean();public CapabilityDescriptor descriptor(){return new CapabilityDescriptor(CODE,"Wiki 知识库",CapabilityType.CONTENT,"提供 Markdown 知识库、RAG 检索和可选图谱增强","i-ri:book-open-line",55,Map.of("vectorStore","neo4j"),List.of("ai","neo4j"));}public CapabilityHealth health(){return enabled.get()?CapabilityHealth.enabled("Wiki 知识库能力已启用",Map.of("vectorStore","neo4j")):CapabilityHealth.disabled("Wiki 知识库能力未启用");}public void enable(Map<String,String> c){enabled.set(true);}public void disable(){enabled.set(false);}public CapabilityTestResult test(String m){return enabled.get()?CapabilityTestResult.success("Wiki 知识库能力可用"):CapabilityTestResult.failure("Wiki 知识库能力未启用");}}
